def _anaplan_list_to_nested(anaplan_list: AnaplanList) -> AnaplanListNested:
    """Convert flat AnaplanList to nested format."""
    attrs = AnaplanListAttributes()
    _populate_anaplan_list_attrs(attrs, anaplan_list)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        anaplan_list, _ANAPLAN_LIST_REL_FIELDS, AnaplanListRelationshipAttributes
    )
    return AnaplanListNested(
        guid=anaplan_list.guid,
        type_name=anaplan_list.type_name,
        status=anaplan_list.status,
        version=anaplan_list.version,
        create_time=anaplan_list.create_time,
        update_time=anaplan_list.update_time,
        created_by=anaplan_list.created_by,
        updated_by=anaplan_list.updated_by,
        classifications=anaplan_list.classifications,
        classification_names=anaplan_list.classification_names,
        meanings=anaplan_list.meanings,
        labels=anaplan_list.labels,
        business_attributes=anaplan_list.business_attributes,
        custom_attributes=anaplan_list.custom_attributes,
        pending_tasks=anaplan_list.pending_tasks,
        proxy=anaplan_list.proxy,
        is_incomplete=anaplan_list.is_incomplete,
        provenance_type=anaplan_list.provenance_type,
        home_id=anaplan_list.home_id,
        depth=anaplan_list.depth,
        immediate_upstream=anaplan_list.immediate_upstream,
        immediate_downstream=anaplan_list.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _anaplan_list_from_nested(nested: AnaplanListNested) -> AnaplanList:
    """Convert nested format to flat AnaplanList."""
    attrs = (
        nested.attributes if nested.attributes is not UNSET else AnaplanListAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _ANAPLAN_LIST_REL_FIELDS,
        AnaplanListRelationshipAttributes,
    )
    return AnaplanList(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_anaplan_list_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _anaplan_list_to_nested_bytes(anaplan_list: AnaplanList, serde: Serde) -> bytes:
    """Convert flat AnaplanList to nested JSON bytes."""
    return serde.encode(_anaplan_list_to_nested(anaplan_list))


def _anaplan_list_from_nested_bytes(data: bytes, serde: Serde) -> AnaplanList:
    """Convert nested JSON bytes to flat AnaplanList."""
    nested = serde.decode(data, AnaplanListNested)
    return _anaplan_list_from_nested(nested)


